provider "aws" {
  region = "ap-southeast-1"
}

data "aws_iam_policy_document" "codebuild_assume_role" {
  statement {
    effect  = "Allow"
    actions = ["sts:AssumeRole"]
    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }
  }
}

data "aws_iam_policy_document" "codebuild_policy" {
  statement {
    effect    = "Allow"
    actions   = ["s3:GetObject", "s3:GetObjectVersion"]
    resources = [
      "arn:aws:s3:::${aws_s3_bucket.primary_source.bucket}/*",
      "arn:aws:s3:::${aws_s3_bucket.secondary_source.bucket}/*"
    ]
  }
  statement {
    effect    = "Allow"
    actions   = ["s3:PutObject"]
    resources = [
      "arn:aws:s3:::${aws_s3_bucket.artifact.bucket}/*"
    ]
  }
  statement {
    effect    = "Allow"
    actions   = ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"]
    resources = ["*"]
  }
}

resource "aws_s3_bucket" "primary_source" {
  bucket_prefix = "primary-source-"
}

resource "aws_s3_bucket" "secondary_source" {
  bucket_prefix = "secondary-source-"
}

resource "aws_s3_bucket" "artifact" {
  bucket_prefix = "artifact-"
}

resource "aws_iam_role" "codebuild" {
  name               = "codebuild-role"
  assume_role_policy = data.aws_iam_policy_document.codebuild_assume_role.json
}

resource "aws_iam_policy" "codebuild_policy" {
  name   = "codebuild-custom-policy"
  policy = data.aws_iam_policy_document.codebuild_policy.json
}

resource "aws_iam_role_policy_attachment" "codebuild_attach" {
  role       = aws_iam_role.codebuild.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

resource "aws_codebuild_project" "example" {
  name         = "example-codebuild-project"
  service_role = aws_iam_role.codebuild.arn

  source {
    type     = "S3"
    location = "${aws_s3_bucket.primary_source.id}/source.zip"
  }

  secondary_sources {
    source_identifier = "secondary"
    type              = "S3"
    location          = "${aws_s3_bucket.secondary_source.id}/secondary.zip"
  }

  artifacts {
    type      = "S3"
    location  = aws_s3_bucket.artifact.id
    packaging = "ZIP"
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:5.0"
    type         = "LINUX_CONTAINER"

    environment_variable {
      name  = "SECRET_VAR"
      type  = "PARAMETER_STORE"
      value = "/some/dummy/path"
    }
  }

  logs_config {
    cloudwatch_logs {
      status = "ENABLED"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "artifact_public_access" {
  bucket = aws_s3_bucket.artifact.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_server_side_encryption_configuration" "artifact_encryption" {
  bucket = aws_s3_bucket.artifact.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_versioning" "artifact_versioning" {
  bucket = aws_s3_bucket.artifact.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "primary_source_public_access" {
  bucket = aws_s3_bucket.primary_source.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_server_side_encryption_configuration" "primary_source_encryption" {
  bucket = aws_s3_bucket.primary_source.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_versioning" "primary_source_versioning" {
  bucket = aws_s3_bucket.primary_source.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "secondary_source_public_access" {
  bucket = aws_s3_bucket.secondary_source.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_server_side_encryption_configuration" "secondary_source_encryption" {
  bucket = aws_s3_bucket.secondary_source.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_versioning" "secondary_source_versioning" {
  bucket = aws_s3_bucket.secondary_source.id

  versioning_configuration {
    status = "Enabled"
  }
}

