provider "aws" {
  region = "ap-southeast-1"
}

data "aws_ami" "amazon_linux" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

data "aws_iam_policy_document" "assume_backup" {
  statement {
    effect = "Allow"
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["backup.amazonaws.com"]
    }
  }
}

resource "aws_backup_vault" "backup_vault" {
  name = "daily-ec2-backup-vault"
}

resource "aws_iam_role" "backup_role" {
  name               = "aws-backup-service-role"
  assume_role_policy = data.aws_iam_policy_document.assume_backup.json
}

resource "aws_iam_role_policy_attachment" "backup_role_policy_attachment" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

resource "aws_backup_plan" "daily_backup" {
  name = "daily-backup-plan"

  rule {
    rule_name         = "daily-midnight"
    target_vault_name = aws_backup_vault.backup_vault.name
    schedule          = "cron(0 0 * * ? *)"
  }
}

resource "aws_backup_selection" "select_instance" {
  name          = "backup-ec2-daily"
  iam_role_arn  = aws_iam_role.backup_role.arn
  plan_id       = aws_backup_plan.daily_backup.id
  resources     = [aws_instance.this.arn]
}

resource "aws_instance" "this" {
  ami           = data.aws_ami.amazon_linux.image_id
  instance_type = "t3.micro"
  ebs_optimized = true

  metadata_options {
    http_tokens = "required"
  }

  root_block_device {
    encrypted = true
  }
}

